import React, { useState } from 'react';
import { documentAPI } from '../services/api';
import './VerifyDocument.css';

const VerifyDocument = () => {
    const [file, setFile] = useState(null);
    const [transactionHash, setTransactionHash] = useState('');
    const [userId, setUserId] = useState('');
    const [loading, setLoading] = useState(false);
    const [result, setResult] = useState(null);
    const [error, setError] = useState(null);

    const handleFileChange = (e) => {
        setFile(e.target.files[0]);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError(null);
        setResult(null);

        if (!file) {
            setError('Please select a file');
            return;
        }
        if (!transactionHash.trim()) {
            setError('Please enter transaction hash');
            return;
        }
        if (!userId.trim()) {
            setError('Please enter user ID');
            return;
        }

        setLoading(true);

        try {
            const response = await documentAPI.verifyDocument(
                file,
                transactionHash,
                userId
            );
            setResult(response.data);
            setFile(null);
            setTransactionHash('');
            setUserId('');
        } catch (err) {
            setError(err.response?.data?.error || 'Verification failed');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="verify-container">
            <h2>Verify Document</h2>

            <form onSubmit={handleSubmit} className="verify-form">
                <div className="form-group">
                    <label>Document File *</label>
                    <input
                        type="file"
                        onChange={handleFileChange}
                        required
                        disabled={loading}
                    />
                    {file && <p className="file-name">✓ {file.name}</p>}
                </div>

                <div className="form-group">
                    <label>Transaction Hash *</label>
                    <input
                        type="text"
                        value={transactionHash}
                        onChange={(e) => setTransactionHash(e.target.value)}
                        placeholder="0x..."
                        disabled={loading}
                        required
                    />
                </div>

                <div className="form-group">
                    <label>User ID (e.g., CE21040) *</label>
                    <input
                        type="text"
                        value={userId}
                        onChange={(e) => setUserId(e.target.value)}
                        placeholder="Student/User ID"
                        disabled={loading}
                        required
                    />
                </div>

                <button type="submit" disabled={loading} className="submit-btn">
                    {loading ? '⏳ Verifying...' : '✓ Verify Document'}
                </button>
            </form>

            {error && (
                <div className="error-box">
                    <strong>❌ Error:</strong> {error}
                </div>
            )}

            {result && (
                <div className={`result-box ${result.success ? 'success' : 'failed'}`}>
                    <h3>{result.success ? '✅ Verification Successful' : '❌ Verification Failed'}</h3>
                    <p><strong>Message:</strong> {result.message}</p>

                    {result.success && (
                        <div className="verification-details">
                            <div className="detail-item">
                                <strong>Hash Match:</strong>
                                <span className={result.hashMatch ? 'valid' : 'invalid'}>
                                    {result.hashMatch ? '✓ YES' : '✗ NO'}
                                </span>
                            </div>

                            <div className="detail-item">
                                <strong>Signature Valid:</strong>
                                <span className={result.signatureValid ? 'valid' : 'invalid'}>
                                    {result.signatureValid ? '✓ YES' : '✗ NO'}
                                </span>
                            </div>

                            <div className="detail-item">
                                <strong>Revocation Status:</strong>
                                <span className={result.revocationStatus === 'NOT REVOKED' ? 'valid' : 'invalid'}>
                                    {result.revocationStatus}
                                </span>
                            </div>

                            <div className="detail-item">
                                <strong>Expiry Date:</strong>
                                <span>{result.expiryDate}</span>
                            </div>

                            <div className="detail-item">
                                <strong>IPFS CID:</strong>
                                <code>{result.ipfsCID.substring(0, 40)}...</code>
                            </div>
                        </div>
                    )}

                    {!result.success && (
                        <div className="failed-details">
                            {result.docHash && <p><strong>Hash:</strong> <code>{result.docHash.substring(0, 40)}...</code></p>}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default VerifyDocument;
